  const [animations, setAnimations] = useState({
    dashFlow: false,
    drawLine: false,
    travelingIcon: false,
    pulsingMarkers: false,
  });

  // Color palette state
  const [colorPalette, setColorPalette] = useState('custom'); // 'custom', 'ocean', 'sunset', 'forest', 'midnight', 'vintage'
  const [mapStyle, setMapStyle] = useState('default'); // 'default', 'minimal', 'satellite', 'vintage', 'dark'

  // Font state
  const [labelFont, setLabelFont] = useState('sans-serif');

  const svgRef = useRef(null); // Ref to access the SVG element

  const extractGPSFromImage = (file, onSuccess) => {
    const reader = new FileReader();
    reader.onload = () => {
      EXIF.getData(file, function () {
        const lat = EXIF.getTag(this, 'GPSLatitude');
        const lng = EXIF.getTag(this, 'GPSLongitude');
        const latRef = EXIF.getTag(this, 'GPSLatitudeRef');
        const lngRef = EXIF.getTag(this, 'GPSLongitudeRef');

        if (lat && lng) {
          const decimalLat =
            (lat[0] + lat[1] / 60 + lat[2] / 3600) * (latRef === 'S' ? -1 : 1);
          const decimalLng =
            (lng[0] + lng[1] / 60 + lng[2] / 3600) * (lngRef === 'W' ? -1 : 1);
          onSuccess(decimalLat, decimalLng);
        } else {
          alert('No GPS data found in the image.');
        }
      });
    };
    reader.readAsArrayBuffer(file);
  };

  const handleOriginImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      extractGPSFromImage(file, (lat, lng) => {
        setOriginLat(lat);
        setOriginLng(lng);
      });
    }
  };

  const handleDestinationImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      extractGPSFromImage(file, (lat, lng) => {
        setDestinationLat(lat);
        setDestinationLng(lng);
      });
    }
  };

  const handleExport = () => {
    const svgElement = svgRef.current.querySelector('svg');
    if (!svgElement) {
      alert('SVG element not found.');
      return;
    }

    // Clone the SVG to avoid modifying the original
    const clonedSvg = svgElement.cloneNode(true);

    // If crop is enabled, set viewBox to crop bounds
    if (cropEnabled) {
      clonedSvg.setAttribute('viewBox', `${cropBounds.x} ${cropBounds.y} ${cropBounds.width} ${cropBounds.height}`);
      clonedSvg.setAttribute('width', cropBounds.width);
      clonedSvg.setAttribute('height', cropBounds.height);

      // Remove the crop overlay from the exported SVG
      const cropOverlay = clonedSvg.querySelector('.crop-overlay');
      if (cropOverlay) {
        cropOverlay.remove();
      }
    }

    const serializer = new XMLSerializer();
    const svgString = serializer.serializeToString(clonedSvg);

    const blob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;

    // Generate file name
    let fileName = Array
      .from(originLabel)
      .filter((c) => c.match(/[a-zA-Z0-9]/))
      .join('');
    fileName += '-';

    fileName += Array
      .from(destinationLabel)
      .filter((c) => c.match(/[a-zA-Z0-9]/))
      .join('');

    fileName += '-by-';
    fileName += travelModeIcon.replace('Fa', '');

    link.download = `${fileName}.svg`;
    link.click();

    URL.revokeObjectURL(url);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
      <Sidebar
        originLat={originLat}
        setOriginLat={setOriginLat}
        originLng={originLng}
        setOriginLng={setOriginLng}
        originLabel={originLabel}
        setOriginLabel={setOriginLabel}
        originColor={originColor}
        setOriginColor={setOriginColor}
        destinationLat={destinationLat}
        setDestinationLat={setDestinationLat}
        destinationLng={destinationLng}
        setDestinationLng={setDestinationLng}
        destinationLabel={destinationLabel}
        setDestinationLabel={setDestinationLabel}
        destinationColor={destinationColor}
        setDestinationColor={setDestinationColor}
        arcColor={arcColor}
        setArcColor={setArcColor}
        arcWidth={arcWidth}
        setArcWidth={setArcWidth}
        arcDashArray={arcDashArray}
        setArcDashArray={setArcDashArray}
        curveHeight={curveHeight}
        setCurveHeight={setCurveHeight}
        handleOriginImageUpload={handleOriginImageUpload}
        handleDestinationImageUpload={handleDestinationImageUpload}
        handleExport={handleExport}
        originIconSize={originIconSize}
        setOriginIconSize={setOriginIconSize}
        destinationIconSize={destinationIconSize}
        setDestinationIconSize={setDestinationIconSize}
        travelModeIcon={travelModeIcon}
        setTravelModeIcon={setTravelModeIcon}
        travelIconColor={travelIconColor}
        setTravelIconColor={setTravelIconColor}
        travelIconSize={travelIconSize}
        setTravelIconSize={setTravelIconSize}
        travelIconRotation={travelIconRotation}
        setTravelIconRotation={setTravelIconRotation}
        originIcon={originIcon}
        setOriginIcon={setOriginIcon}
        destinationIcon={destinationIcon}
        setDestinationIcon={setDestinationIcon}
        labelSize={labelSize}
        setLabelSize={setLabelSize}
        labelPosition={labelPosition}
        setLabelPosition={setLabelPosition}
        theme={theme}
        setTheme={setTheme}
        cropEnabled={cropEnabled}
        setCropEnabled={setCropEnabled}
        cropBounds={cropBounds}
        setCropBounds={setCropBounds}
        cropAspectRatio={cropAspectRatio}
        setCropAspectRatio={setCropAspectRatio}
        animations={animations}
        setAnimations={setAnimations}
        colorPalette={colorPalette}
        setColorPalette={setColorPalette}
        mapStyle={mapStyle}
        setMapStyle={setMapStyle}
        labelFont={labelFont}
        setLabelFont={setLabelFont}
        setOriginColor={setOriginColor}
        setDestinationColor={setDestinationColor}
        setArcColor={setArcColor}
        setTravelIconColor={setTravelIconColor}
      />
      <div style={{ flex: 1 }}>
        <FlightMap
          ref={svgRef}
          startPoint={{ lat: originLat, lng: originLng }}
          endPoint={{ lat: destinationLat, lng: destinationLng }}
          arcColor={arcColor}
          arcWidth={arcWidth}
          arcDashArray={`${arcDashArray},${arcDashArray}`}
          curveHeight={curveHeight}
          originIconSize={originIconSize}
          destinationIconSize={destinationIconSize}
          travelModeIcon={travelModeIcon}
          travelIconColor={travelIconColor}
          travelIconSize={travelIconSize}
          originColor={originColor}
          destinationColor={destinationColor}
          originIcon={originIcon}
          destinationIcon={destinationIcon}
          travelIconRotation={travelIconRotation}
          originLabel={originLabel}
          destinationLabel={destinationLabel}
          labelSize={labelSize}
          labelPosition={labelPosition}
          theme={theme}
          cropEnabled={cropEnabled}
          cropBounds={cropBounds}
          setCropBounds={setCropBounds}
          cropAspectRatio={cropAspectRatio}
        />
      </div>
    </div>
  );
}

export default App;

import React, { forwardRef, useState, useCallback } from 'react';
import { ComposableMap, Geographies, Geography, Marker, ZoomableGroup } from 'react-simple-maps';
import {
    FaPlane,
    FaCar,
    FaTrain,
    FaHorse,
    FaMapMarkerAlt,
    FaFlagCheckered,
    FaHome,
    FaBuilding,
    FaTree,
    FaMountain,
    FaUmbrellaBeach,
    FaBicycle,
} from 'react-icons/fa';


// Icons definition
const availableIcons = {
    FaPlane: <FaPlane />,
    FaCar: <FaCar />,
    FaTrain: <FaTrain />,
    FaBicycle: <FaBicycle />,
    FaHorse: <FaHorse />,
    FaMapMarkerAlt: <FaMapMarkerAlt />,
    FaFlagCheckered: <FaFlagCheckered />,
    FaHome: <FaHome />,
    FaBuilding: <FaBuilding />,
    FaTree: <FaTree />,
    FaMountain: <FaMountain />,
    FaUmbrellaBeach: <FaUmbrellaBeach />,
};

const FlightMap = forwardRef(
    (
        {
            startPoint,
            endPoint,
            arcColor,
            arcWidth,
            arcDashArray,
            curveHeight,
            originIconSize,
            destinationIconSize,
            travelModeIcon,
            travelIconColor,
            travelIconSize,
            originColor,
            destinationColor,
            originIcon = 'FaMapMarkerAlt',
            destinationIcon = 'FaFlagCheckered',
            originLabel,
            destinationLabel,
            labelSize,
            labelPosition,
            theme = 'light',
            cropEnabled = false,
            cropBounds = { x: 100, y: 100, width: 400, height: 300 },
            setCropBounds,
            cropAspectRatio = 'free',
        },
        ref
    ) => {
        const [isDragging, setIsDragging] = useState(false);
        const [isResizing, setIsResizing] = useState(false);
        const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

        // Parse aspect ratio string to number
        const getAspectRatioValue = (ratio) => {
            if (ratio === 'free') return null;
            const [w, h] = ratio.split(':').map(Number);
            return w / h;
        };

        const handleCropMouseDown = useCallback((e) => {
            if (!cropEnabled) return;
            const rect = e.currentTarget.getBoundingClientRect();
            setDragStart({ x: e.clientX - rect.left - cropBounds.x, y: e.clientY - rect.top - cropBounds.y });
            setIsDragging(true);
        }, [cropEnabled, cropBounds.x, cropBounds.y]);

        const handleResizeMouseDown = useCallback((e) => {
            e.stopPropagation();
            if (!cropEnabled) return;
            setIsResizing(true);
        }, [cropEnabled]);

        const handleMouseMove = useCallback((e) => {
            if (!cropEnabled || (!isDragging && !isResizing)) return;
            const rect = e.currentTarget.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            if (isDragging) {
                setCropBounds(prev => ({
                    ...prev,
                    x: Math.max(0, x - dragStart.x),
                    y: Math.max(0, y - dragStart.y),
                }));
            } else if (isResizing) {
                const aspectRatio = getAspectRatioValue(cropAspectRatio);
                let newWidth = Math.max(50, x - cropBounds.x);
                let newHeight = Math.max(50, y - cropBounds.y);

                if (aspectRatio) {
                    // Maintain aspect ratio - use width as the driver
                    newHeight = newWidth / aspectRatio;
                }

                setCropBounds(prev => ({
                    ...prev,
                    width: newWidth,
                    height: newHeight,
                }));
            }
        }, [cropEnabled, isDragging, isResizing, dragStart, setCropBounds, cropAspectRatio, cropBounds.x]);

        const handleMouseUp = useCallback(() => {
            setIsDragging(false);
            setIsResizing(false);
        }, []);
        // Theme-based colors
        const themeColors = {
            light: {
                background: '#FFFFFF',
                geographyFill: '#DDD',
                geographyStroke: '#FFF',
                labelColor: '#000000',
            },
            dark: {
                background: '#1a1a1a',
                geographyFill: '#333',
                geographyStroke: '#222',
                labelColor: '#FFFFFF',
            },
        };
        const colors = themeColors[theme] || themeColors.light;
        const calculateArcPath = (projection, start, end) => {
            const start2D = projection([start.lng, start.lat]);
            const end2D = projection([end.lng, end.lat]);
            if (!start2D || !end2D) return '';
            const midX = (start2D[0] + end2D[0]) / 2;
            const midY = (start2D[1] + end2D[1]) / 2 - curveHeight * 100;
            return `M ${start2D[0]},${start2D[1]} Q ${midX},${midY} ${end2D[0]},${end2D[1]}`;
        };

        const getLabelXOffset = (position, iconSize, labelSize) => {
            switch (position) {
                case 'right':
                    return iconSize
                case 'left':
                    return -(iconSize * 1.2); // Place label to the left of the icon
                default:
                    return 0; // Center for top or bottom
            }
        };

        const getLabelYOffset = (position, iconSize, labelSize) => {
            switch (position) {
                case 'top':
                    return -(iconSize * 1.2 + labelSize * 0.1); // Place label above the icon
                case 'bottom':
                    return iconSize * 1.2 + labelSize * 0.6; // Place label below the icon
                default:
                    return labelSize * 0.3; // Slight vertical adjustment for left/right
            }
        };


        return (
            <div
                ref={ref}
                style={{ width: '100%', height: '100%', backgroundColor: colors.background, position: 'relative' }}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onMouseLeave={handleMouseUp}
            >
                <ComposableMap projection="geoMercator" style={{ width: '100%', height: '100%', backgroundColor: colors.background }}>
                    <ZoomableGroup>
                        <Geographies geography="https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json">
                            {({ geographies, projection }) => (
                                <>
                                    {geographies.map((geo) => (
                                        <Geography key={geo.rsmKey} geography={geo} fill={colors.geographyFill} stroke={colors.geographyStroke} />
                                    ))}
                                    <path
                                        d={calculateArcPath(projection, startPoint, endPoint)}
                                        fill="none"
                                        stroke={arcColor}
                                        strokeWidth={arcWidth}
                                        strokeDasharray={arcDashArray}
                                    />
                                    {/* Travel Icon */}
                                    {(() => {
                                        const start2D = projection([startPoint.lng, startPoint.lat]);
                                        const end2D = projection([endPoint.lng, endPoint.lat]);
                                        if (!start2D || !end2D || !travelModeIcon) return null;

                                        const iconX = (start2D[0] + end2D[0]) / 2;
                                        const iconY = (start2D[1] + end2D[1]) / 2 - curveHeight * 50;

                                        return (
                                            <g transform={`translate(${iconX}, ${iconY})`}>
                                                <circle
                                                    r={travelIconSize * 0.8}
                                                    fill={travelIconColor}
                                                />
                                                <g transform={`translate(${-travelIconSize / 2}, ${-travelIconSize / 2})`}>
                                                    {availableIcons[travelModeIcon] &&
                                                        React.cloneElement(availableIcons[travelModeIcon], {
                                                            size: travelIconSize,
                                                            color: 'white',
                                                        })}
                                                </g>
                                            </g>
                                        );
                                    })()}
                                </>
                            )}
                        </Geographies>

                        {/* Origin Marker */}
                        <Marker coordinates={[startPoint.lng, startPoint.lat]}>
                            <g>
                                {/* Draw Circle */}
                                <circle
                                    r={originIconSize * 0.8}
                                    fill={originColor}
                                />
                                {/* Draw Icon */}
                                <g transform={`translate(${-originIconSize / 2}, ${-originIconSize / 2})`}>
                                    {availableIcons[originIcon] &&
                                        React.cloneElement(availableIcons[originIcon], {
                                            size: originIconSize,
                                            color: 'white',
                                        })}
                                </g>
                                {/* Draw Label */}
                                <text
                                    x={getLabelXOffset(labelPosition, originIconSize)}
                                    y={getLabelYOffset(labelPosition, originIconSize, labelSize)}
                                    textAnchor={labelPosition === 'right' ? 'start' : labelPosition === 'left' ? 'end' : 'middle'}
                                    alignmentBaseline={labelPosition === 'top' || labelPosition === 'bottom' ? 'central' : 'middle'}
                                    fontSize={labelSize}
                                    fill={colors.labelColor}
                                >
                                    {originLabel}
                                </text>
                            </g>
                        </Marker>


                        {/* Destination Marker */}
                        <Marker coordinates={[endPoint.lng, endPoint.lat]}>
                            <g>
                                <circle
                                    r={destinationIconSize * 0.8}
                                    fill={destinationColor}
                                />
                                <g transform={`translate(${-destinationIconSize / 2}, ${-destinationIconSize / 2})`}>
                                    {availableIcons[destinationIcon] &&
                                        React.cloneElement(availableIcons[destinationIcon], {
                                            size: destinationIconSize,
                                            color: 'white',
                                        })}
                                </g>
                                <text
                                    x={getLabelXOffset(labelPosition, destinationIconSize, labelSize)}
                                    y={getLabelYOffset(labelPosition, destinationIconSize, labelSize)}
                                    textAnchor={labelPosition === 'right' ? 'start' : labelPosition === 'left' ? 'end' : 'middle'}
                                    alignmentBaseline={labelPosition === 'top' || labelPosition === 'bottom' ? 'central' : 'middle'}
                                    fontSize={labelSize}
                                    fill={colors.labelColor}
                                >
                                    {destinationLabel}
                                </text>
                            </g>
                        </Marker>
                    </ZoomableGroup>
                </ComposableMap>

                {/* Crop Selection Overlay */}
                {cropEnabled && (
                    <div
                        className="crop-overlay"
                        style={{
                            position: 'absolute',
                            left: cropBounds.x,
                            top: cropBounds.y,
                            width: cropBounds.width,
                            height: cropBounds.height,
                            border: '2px dashed #3b82f6',
                            backgroundColor: 'rgba(59, 130, 246, 0.1)',
                            cursor: isDragging ? 'grabbing' : 'grab',
                            boxSizing: 'border-box',
                        }}
                        onMouseDown={handleCropMouseDown}
                    >
                        {/* Resize handle */}
                        <div
                            style={{
                                position: 'absolute',
                                right: -6,
                                bottom: -6,
                                width: 12,
                                height: 12,
                                backgroundColor: '#3b82f6',
                                cursor: 'nwse-resize',
                                borderRadius: 2,
                            }}
                            onMouseDown={handleResizeMouseDown}
                        />
                        {/* Size indicator */}
                        <div
                            style={{
                                position: 'absolute',
                                bottom: 4,
                                left: 4,
                                fontSize: 10,
                                color: '#3b82f6',
                                fontWeight: 'bold',
                                backgroundColor: 'rgba(255,255,255,0.8)',
                                padding: '1px 4px',
                                borderRadius: 2,
                            }}
                        >
                            {Math.round(cropBounds.width)} x {Math.round(cropBounds.height)}
                        </div>
                    </div>
                )}

                {/* Dark overlay outside crop area */}
                {cropEnabled && (
                    <>
                        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: cropBounds.y, backgroundColor: 'rgba(0,0,0,0.4)', pointerEvents: 'none' }} />
                        <div style={{ position: 'absolute', top: cropBounds.y, left: 0, width: cropBounds.x, height: cropBounds.height, backgroundColor: 'rgba(0,0,0,0.4)', pointerEvents: 'none' }} />
                        <div style={{ position: 'absolute', top: cropBounds.y, left: cropBounds.x + cropBounds.width, right: 0, height: cropBounds.height, backgroundColor: 'rgba(0,0,0,0.4)', pointerEvents: 'none' }} />
                        <div style={{ position: 'absolute', top: cropBounds.y + cropBounds.height, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.4)', pointerEvents: 'none' }} />
                    </>
                )}
            </div>
        );
    }
);

export default FlightMap;

