                onMouseLeave={handleMouseUp}
            >
                <style>{animationStyles}</style>
                <ComposableMap projection="geoMercator" style={{ width: '100%', height: '100%', backgroundColor: colors.background }}>
                    <ZoomableGroup>
                        <Geographies geography="https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json">
                            {({ geographies, projection }) => (
                                <>
                                    {geographies.map((geo) => (
                                        <Geography key={geo.rsmKey} geography={geo} fill={colors.geographyFill} stroke={colors.geographyStroke} />
                                    ))}
                                    <path
                                        d={calculateArcPath(projection, startPoint, endPoint)}
                                        fill="none"
                                        stroke={arcColor}
                                        strokeWidth={arcWidth}
                                        strokeDasharray={animations.drawLine ? '1000' : arcDashArray}
                                        style={{
                                            animation: animations.dashFlow
