                                    fontSize={labelSize}
                                    fontFamily={labelFont}
                                    fill={colors.labelColor}
                                >
                                    {destinationLabel}
                                </text>
                            </g>
                        </Marker>
                    </ZoomableGroup>
                </ComposableMap>

                {/* Crop Selection Overlay */}
                {cropEnabled && (
                    <div
                        className="crop-overlay"
