                                backgroundColor: '#3b82f6',
                                cursor: 'nwse-resize',
                                borderRadius: 2,
                            }}
                            onMouseDown={handleResizeMouseDown}
                        />
                        {/* Size indicator */}
                        <div
                            style={{
                                position: 'absolute',
                                bottom: 4,
                                left: 4,
                                fontSize: 10,
                                color: '#3b82f6',
                                fontWeight: 'bold',
                                backgroundColor: 'rgba(255,255,255,0.8)',
                                padding: '1px 4px',
                                borderRadius: 2,
                            }}
