import React, { useState, useRef } from 'react';
import EXIF from 'exif-js';
import JSZip from 'jszip';
import Sidebar from './components/Sidebar';
import FlightMap from './components/FlightMap';

function App() {
  const [originLat, setOriginLat] = useState(49.0078593);
  const [originLng, setOriginLng] = useState(8.4010293);
  const [destinationLat, setDestinationLat] = useState(40.6973709);
  const [destinationLng, setDestinationLng] = useState(-74.144487);
  const [originLabel, setOriginLabel] = useState('Karlsruhe');
  const [destinationLabel, setDestinationLabel] = useState('New York');
  const [originColor, setOriginColor] = useState('#0000ff');
  const [destinationColor, setDestinationColor] = useState('#ff0000');
  const [arcColor, setArcColor] = useState('#00ff00');
  const [arcWidth, setArcWidth] = useState(2);
  const [arcDashArray, setArcDashArray] = useState(5);
  const [curveHeight, setCurveHeight] = useState(0.5);

  // Icon states
  const [originIconSize, setOriginIconSize] = useState(10);
  const [destinationIconSize, setDestinationIconSize] = useState(10);
  const [travelModeIcon, setTravelModeIcon] = useState('FaPlane');
  const [travelIconColor, setTravelIconColor] = useState('#ff6600');
  const [travelIconSize, setTravelIconSize] = useState(10);
  const [originIcon, setOriginIcon] = useState('FaMapMarkerAlt');
  const [destinationIcon, setDestinationIcon] = useState('FaFlagCheckered');
  const [travelIconRotation, setTravelIconRotation] = useState(0);

  // Label states
  const [labelSize, setLabelSize] = useState(12);
  const [labelPosition, setLabelPosition] = useState('top');

  // Theme state: 'light' or 'dark'
  const [theme, setTheme] = useState('light');

  // Crop/selection state
  const [cropEnabled, setCropEnabled] = useState(false);
  const [cropBounds, setCropBounds] = useState({ x: 100, y: 100, width: 400, height: 300 });
  const [cropAspectRatio, setCropAspectRatio] = useState('free');

  // Animation state
  const [animations, setAnimations] = useState({
    dashFlow: false,
    drawLine: false,
    travelingIcon: false,
    pulsingMarkers: false,
  });

  // Color palette state
  const [colorPalette, setColorPalette] = useState('custom'); // 'custom', 'ocean', 'sunset', 'forest', 'midnight', 'vintage'
  const [mapStyle, setMapStyle] = useState('default'); // 'default', 'minimal', 'satellite', 'vintage', 'dark'

  // Font state
  const [labelFont, setLabelFont] = useState('sans-serif');

  const svgRef = useRef(null); // Ref to access the SVG element

  const extractGPSFromImage = (file, onSuccess) => {
    const reader = new FileReader();
    reader.onload = () => {
      EXIF.getData(file, function () {
        const lat = EXIF.getTag(this, 'GPSLatitude');
        const lng = EXIF.getTag(this, 'GPSLongitude');
        const latRef = EXIF.getTag(this, 'GPSLatitudeRef');
        const lngRef = EXIF.getTag(this, 'GPSLongitudeRef');

        if (lat && lng) {
          const decimalLat =
            (lat[0] + lat[1] / 60 + lat[2] / 3600) * (latRef === 'S' ? -1 : 1);
          const decimalLng =
            (lng[0] + lng[1] / 60 + lng[2] / 3600) * (lngRef === 'W' ? -1 : 1);
          onSuccess(decimalLat, decimalLng);
        } else {
          alert('No GPS data found in the image.');
        }
      });
    };
    reader.readAsArrayBuffer(file);
  };

  const handleOriginImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      extractGPSFromImage(file, (lat, lng) => {
        setOriginLat(lat);
        setOriginLng(lng);
      });
    }
  };

  const handleDestinationImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      extractGPSFromImage(file, (lat, lng) => {
        setDestinationLat(lat);
        setDestinationLng(lng);
      });
    }
  };

  const handleExport = () => {
    const svgElement = svgRef.current.querySelector('svg');
    if (!svgElement) {
      alert('SVG element not found.');
      return;
    }

    // Clone the SVG to avoid modifying the original
    const clonedSvg = svgElement.cloneNode(true);

    // If crop is enabled, transform screen coordinates to SVG coordinates
    if (cropEnabled) {
      // Get the SVG's current viewBox and dimensions
      const svgRect = svgElement.getBoundingClientRect();
      const viewBox = svgElement.viewBox.baseVal;

      // Calculate scale factors between screen pixels and SVG units
      const scaleX = viewBox.width / svgRect.width;
      const scaleY = viewBox.height / svgRect.height;

      // Transform crop bounds from screen coordinates to SVG coordinates
      const svgCropX = viewBox.x + (cropBounds.x * scaleX);
      const svgCropY = viewBox.y + (cropBounds.y * scaleY);
      const svgCropWidth = cropBounds.width * scaleX;
      const svgCropHeight = cropBounds.height * scaleY;

      clonedSvg.setAttribute('viewBox', `${svgCropX} ${svgCropY} ${svgCropWidth} ${svgCropHeight}`);
      clonedSvg.setAttribute('width', cropBounds.width);
      clonedSvg.setAttribute('height', cropBounds.height);
    }

    const serializer = new XMLSerializer();
    const svgString = serializer.serializeToString(clonedSvg);

    const blob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;

    // Generate file name
    let fileName = Array
      .from(originLabel)
      .filter((c) => c.match(/[a-zA-Z0-9]/))
      .join('');
    fileName += '-';

    fileName += Array
      .from(destinationLabel)
      .filter((c) => c.match(/[a-zA-Z0-9]/))
      .join('');

    fileName += '-by-';
    fileName += travelModeIcon.replace('Fa', '');

    link.download = `${fileName}.svg`;
    link.click();

    URL.revokeObjectURL(url);
  };

  const handleExportZip = async () => {
    const svgElement = svgRef.current.querySelector('svg');
    if (!svgElement) {
      alert('SVG element not found.');
      return;
    }

    // Generate base file name
    let baseName = Array.from(originLabel).filter((c) => c.match(/[a-zA-Z0-9]/)).join('');
    baseName += '-';
    baseName += Array.from(destinationLabel).filter((c) => c.match(/[a-zA-Z0-9]/)).join('');
    baseName += '-by-' + travelModeIcon.replace('Fa', '');

    // Clone and prepare SVG
    const clonedSvg = svgElement.cloneNode(true);

    // Handle crop if enabled
    if (cropEnabled) {
      const svgRect = svgElement.getBoundingClientRect();
      const viewBox = svgElement.viewBox.baseVal;
      const scaleX = viewBox.width / svgRect.width;
      const scaleY = viewBox.height / svgRect.height;
      const svgCropX = viewBox.x + (cropBounds.x * scaleX);
      const svgCropY = viewBox.y + (cropBounds.y * scaleY);
      const svgCropWidth = cropBounds.width * scaleX;
      const svgCropHeight = cropBounds.height * scaleY;
      clonedSvg.setAttribute('viewBox', `${svgCropX} ${svgCropY} ${svgCropWidth} ${svgCropHeight}`);
      clonedSvg.setAttribute('width', cropBounds.width);
      clonedSvg.setAttribute('height', cropBounds.height);
    }

    // Add animation classes to SVG elements
    const arcPath = clonedSvg.querySelector('path[stroke][fill="none"]');
    if (arcPath) {
      if (animations.dashFlow) arcPath.classList.add('arc-dash-flow');
      if (animations.drawLine) arcPath.classList.add('arc-draw-line');
    }

    // Add class to markers for pulsing
    const markers = clonedSvg.querySelectorAll('g[transform]');
    if (animations.pulsingMarkers) {
      markers.forEach((m, i) => m.classList.add('marker-pulse', `marker-${i}`));
    }

    // Add link to external CSS
    const styleLink = document.createElementNS('http://www.w3.org/2000/svg', 'style');
    styleLink.textContent = '@import url("animations.css");';
    clonedSvg.insertBefore(styleLink, clonedSvg.firstChild);

    const serializer = new XMLSerializer();
    const svgString = serializer.serializeToString(clonedSvg);

    // Generate CSS file content
    const cssContent = `/* Flight Path Animations */
/* Generated by Dynamic Travel Path Visualizer */

/* Flowing dashes animation */
@keyframes dashFlow {
  from { stroke-dashoffset: 0; }
  to { stroke-dashoffset: -40; }
}

.arc-dash-flow {
  animation: dashFlow 1s linear infinite;
}

/* Draw line animation */
@keyframes drawLine {
  from { stroke-dashoffset: 2000; }
  to { stroke-dashoffset: 0; }
}

.arc-draw-line {
  stroke-dasharray: 2000;
  animation: drawLine 2s ease-out forwards;
}

/* Pulsing markers animation */
@keyframes pulse {
  0%, 100% { transform: scale(1); opacity: 1; }
  50% { transform: scale(1.2); opacity: 0.8; }
}

.marker-pulse {
  transform-origin: center;
  transform-box: fill-box;
  animation: pulse 1.5s ease-in-out infinite;
}

.marker-1 {
  animation-delay: 0.75s;
}

/* Traveling icon animation */
@keyframes travelIcon {
  0% { offset-distance: 0%; }
  100% { offset-distance: 100%; }
}

.travel-icon-animated {
  offset-rotate: 0deg;
  animation: travelIcon 3s ease-in-out infinite;
}
`;

    // Generate HTML preview file
    const htmlContent = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${baseName} - Flight Path</title>
  <link rel="stylesheet" href="animations.css">
  <style>
    body {
      margin: 0;
      display: flex;
      justify-content: center;
      align-items: center;
      min-height: 100vh;
      background: #f0f0f0;
    }
    .container {
      max-width: 100%;
      padding: 20px;
    }
    object, img {
      max-width: 100%;
      height: auto;
    }
  </style>
</head>
<body>
  <div class="container">
    <!-- Use object tag to enable CSS animations -->
    <object type="image/svg+xml" data="${baseName}.svg" width="100%">
      <!-- Fallback to img if object doesn't work -->
      <img src="${baseName}.svg" alt="Flight path from ${originLabel} to ${destinationLabel}">
    </object>
  </div>
</body>
</html>
`;

    // Generate README
    const readmeContent = `# ${baseName} Flight Path

## Files Included
- \`${baseName}.svg\` - The flight path SVG graphic
- \`animations.css\` - CSS animations for the SVG
- \`preview.html\` - HTML file to preview the animated SVG

## Usage

### Option 1: Use the HTML preview
Simply open \`preview.html\` in a web browser to see the animated flight path.

### Option 2: Embed in your website
1. Copy both \`${baseName}.svg\` and \`animations.css\` to your website
2. Link the CSS in your HTML:
   \`\`\`html
   <link rel="stylesheet" href="animations.css">
   \`\`\`
3. Embed the SVG using an object tag (required for CSS animations):
   \`\`\`html
   <object type="image/svg+xml" data="${baseName}.svg" width="800"></object>
   \`\`\`

### Option 3: Inline SVG
For full animation support, you can also inline the SVG directly in your HTML and include the CSS.

## Animations Included
${animations.dashFlow ? '- ✅ Flowing dashes along the path\n' : ''}${animations.drawLine ? '- ✅ Line drawing effect\n' : ''}${animations.pulsingMarkers ? '- ✅ Pulsing origin/destination markers\n' : ''}${animations.travelingIcon ? '- ✅ Traveling icon along path\n' : ''}
## Generated with
Dynamic Travel Path Visualizer
`;

    // Create ZIP file
    const zip = new JSZip();
    zip.file(`${baseName}.svg`, svgString);
    zip.file('animations.css', cssContent);
    zip.file('preview.html', htmlContent);
    zip.file('README.md', readmeContent);

    // Generate and download
    const zipBlob = await zip.generateAsync({ type: 'blob' });
    const url = URL.createObjectURL(zipBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${baseName}.zip`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
      <Sidebar
        originLat={originLat}
        setOriginLat={setOriginLat}
        originLng={originLng}
        setOriginLng={setOriginLng}
        originLabel={originLabel}
        setOriginLabel={setOriginLabel}
        originColor={originColor}
        setOriginColor={setOriginColor}
        destinationLat={destinationLat}
