{/* Travel Icon */}
{(() => {
    const start2D = projection([startPoint.lng, startPoint.lat]);
    const end2D = projection([endPoint.lng, endPoint.lat]);
    if (!start2D || !end2D || !travelModeIcon) return null;

    const iconX = (start2D[0] + end2D[0]) / 2;
    const iconY = (start2D[1] + end2D[1]) / 2 - curveHeight * 50;
    const pathD = calculateArcPath(projection, startPoint, endPoint);

    // Calculate angle from icon position to destination
    const dx = end2D[0] - iconX;
    const dy = end2D[1] - iconY;
    const angleDeg = (Math.atan2(dy, dx) * 180) / Math.PI;

    // Icons that point right by default and can be rotated/flipped
    const canTransform = ['FaPlane', 'FaBicycle', 'FaHorse'].includes(travelModeIcon);

    // If angle > 90 or < -90, icon would be upside down, so flip instead
    const needsFlip = Math.abs(angleDeg) > 90;

    // Adjust rotation angle when flipped
    const rotationAngle = needsFlip
        ? (angleDeg > 0 ? angleDeg - 180 : angleDeg + 180)
        : angleDeg;

    // Build transform: flip first (if needed), then rotate
    let iconTransform = '';
    if (canTransform) {
        if (needsFlip) {
            iconTransform = `scale(-1, 1) rotate(${-rotationAngle})`;
        } else {
            iconTransform = `rotate(${rotationAngle})`;
        }
    }

    return (
        <g
            style={animations.travelingIcon ? {
                offsetPath: `path('${pathD}')`,
                animation: 'travelIcon 3s ease-in-out infinite',
            } : { transform: `translate(${iconX}px, ${iconY}px)` }}
