import React, { useState, useRef, useEffect } from 'react';
import EXIF from 'exif-js';
import JSZip from 'jszip';
import Sidebar from './components/Sidebar';
import FlightMap from './components/FlightMap';

// Helper to get value from localStorage with fallback
const getStoredValue = (key, defaultValue) => {
  try {
    const stored = localStorage.getItem(`flightPath_${key}`);
    if (stored !== null) {
      return JSON.parse(stored);
    }
  } catch (e) {
    console.warn(`Error reading ${key} from localStorage:`, e);
  }
  return defaultValue;
};

function App() {
  const [originLat, setOriginLat] = useState(() => getStoredValue('originLat', 49.0078593));
  const [originLng, setOriginLng] = useState(() => getStoredValue('originLng', 8.4010293));
  const [destinationLat, setDestinationLat] = useState(() => getStoredValue('destinationLat', 40.6973709));
  const [destinationLng, setDestinationLng] = useState(() => getStoredValue('destinationLng', -74.144487));
  const [originLabel, setOriginLabel] = useState(() => getStoredValue('originLabel', 'Karlsruhe'));
  const [destinationLabel, setDestinationLabel] = useState(() => getStoredValue('destinationLabel', 'New York'));
  const [originColor, setOriginColor] = useState(() => getStoredValue('originColor', '#0000ff'));
  const [destinationColor, setDestinationColor] = useState(() => getStoredValue('destinationColor', '#ff0000'));
  const [arcColor, setArcColor] = useState(() => getStoredValue('arcColor', '#00ff00'));
  const [arcWidth, setArcWidth] = useState(() => getStoredValue('arcWidth', 2));
  const [arcDashArray, setArcDashArray] = useState(() => getStoredValue('arcDashArray', 5));
  const [curveHeight, setCurveHeight] = useState(() => getStoredValue('curveHeight', 0.5));

  // Icon states
  const [originIconSize, setOriginIconSize] = useState(() => getStoredValue('originIconSize', 10));
  const [destinationIconSize, setDestinationIconSize] = useState(() => getStoredValue('destinationIconSize', 10));
  const [travelModeIcon, setTravelModeIcon] = useState(() => getStoredValue('travelModeIcon', 'FaPlane'));
  const [travelIconColor, setTravelIconColor] = useState(() => getStoredValue('travelIconColor', '#ff6600'));
  const [travelIconSize, setTravelIconSize] = useState(() => getStoredValue('travelIconSize', 10));
  const [originIcon, setOriginIcon] = useState(() => getStoredValue('originIcon', 'FaMapMarkerAlt'));
  const [destinationIcon, setDestinationIcon] = useState(() => getStoredValue('destinationIcon', 'FaFlagCheckered'));
  const [travelIconRotation, setTravelIconRotation] = useState(() => getStoredValue('travelIconRotation', 0));

  // Label states
  const [labelSize, setLabelSize] = useState(() => getStoredValue('labelSize', 12));
  const [labelPosition, setLabelPosition] = useState(() => getStoredValue('labelPosition', 'top'));

  // Theme state: 'light' or 'dark'
  const [theme, setTheme] = useState(() => getStoredValue('theme', 'light'));

  // Crop/selection state (don't persist crop bounds as they depend on screen size)
  const [cropEnabled, setCropEnabled] = useState(false);
  const [cropBounds, setCropBounds] = useState({ x: 100, y: 100, width: 400, height: 300 });
  const [cropAspectRatio, setCropAspectRatio] = useState(() => getStoredValue('cropAspectRatio', 'free'));

  // Animation state
  const [animations, setAnimations] = useState(() => getStoredValue('animations', {
    dashFlow: false,
    drawLine: false,
    travelingIcon: false,
    pulsingMarkers: false,
  }));

