import React, { useState, useRef, useEffect } from 'react';
import EXIF from 'exif-js';
import JSZip from 'jszip';
import Sidebar from './components/Sidebar';
import FlightMap from './components/FlightMap';

// Helper to get value from localStorage with fallback
const getStoredValue = (key, defaultValue) => {
  try {
    const stored = localStorage.getItem(`flightPath_${key}`);
    if (stored !== null) {
      return JSON.parse(stored);
    }
  } catch (e) {
    console.warn(`Error reading ${key} from localStorage:`, e);
  }
  return defaultValue;
};

function App() {
  const [originLat, setOriginLat] = useState(() => getStoredValue('originLat', 49.0078593));
  const [originLng, setOriginLng] = useState(() => getStoredValue('originLng', 8.4010293));
  const [destinationLat, setDestinationLat] = useState(() => getStoredValue('destinationLat', 40.6973709));
  const [destinationLng, setDestinationLng] = useState(() => getStoredValue('destinationLng', -74.144487));
  const [originLabel, setOriginLabel] = useState(() => getStoredValue('originLabel', 'Karlsruhe'));
  const [destinationLabel, setDestinationLabel] = useState(() => getStoredValue('destinationLabel', 'New York'));
  const [originColor, setOriginColor] = useState(() => getStoredValue('originColor', '#0000ff'));
  const [destinationColor, setDestinationColor] = useState(() => getStoredValue('destinationColor', '#ff0000'));
  const [arcColor, setArcColor] = useState(() => getStoredValue('arcColor', '#00ff00'));
  const [arcWidth, setArcWidth] = useState(() => getStoredValue('arcWidth', 2));
  const [arcDashArray, setArcDashArray] = useState(() => getStoredValue('arcDashArray', 5));
  const [curveHeight, setCurveHeight] = useState(() => getStoredValue('curveHeight', 0.5));

  // Icon states
  const [originIconSize, setOriginIconSize] = useState(() => getStoredValue('originIconSize', 10));
  const [destinationIconSize, setDestinationIconSize] = useState(() => getStoredValue('destinationIconSize', 10));
  const [travelModeIcon, setTravelModeIcon] = useState(() => getStoredValue('travelModeIcon', 'FaPlane'));
  const [travelIconColor, setTravelIconColor] = useState(() => getStoredValue('travelIconColor', '#ff6600'));
  const [travelIconSize, setTravelIconSize] = useState(() => getStoredValue('travelIconSize', 10));
  const [originIcon, setOriginIcon] = useState(() => getStoredValue('originIcon', 'FaMapMarkerAlt'));
  const [destinationIcon, setDestinationIcon] = useState(() => getStoredValue('destinationIcon', 'FaFlagCheckered'));
  const [travelIconRotation, setTravelIconRotation] = useState(() => getStoredValue('travelIconRotation', 0));

  // Label states
  const [labelSize, setLabelSize] = useState(() => getStoredValue('labelSize', 12));
  const [labelPosition, setLabelPosition] = useState(() => getStoredValue('labelPosition', 'top'));

  // Theme state: 'light' or 'dark'
  const [theme, setTheme] = useState(() => getStoredValue('theme', 'light'));

  // Crop/selection state (don't persist crop bounds as they depend on screen size)
  const [cropEnabled, setCropEnabled] = useState(false);
  const [cropBounds, setCropBounds] = useState({ x: 100, y: 100, width: 400, height: 300 });
  const [cropAspectRatio, setCropAspectRatio] = useState(() => getStoredValue('cropAspectRatio', 'free'));

  // Animation state
  const [animations, setAnimations] = useState(() => getStoredValue('animations', {
    dashFlow: false,
    drawLine: false,
    travelingIcon: false,
    pulsingMarkers: false,
  }));

  // Color palette state
  const [colorPalette, setColorPalette] = useState(() => getStoredValue('colorPalette', 'custom'));
  const [mapStyle, setMapStyle] = useState(() => getStoredValue('mapStyle', 'default'));

  // Font state
  const [labelFont, setLabelFont] = useState(() => getStoredValue('labelFont', 'sans-serif'));

  const svgRef = useRef(null); // Ref to access the SVG element

  // Save all settings to localStorage whenever they change
  useEffect(() => {
    const settings = {
      originLat, originLng, destinationLat, destinationLng,
      originLabel, destinationLabel,
      originColor, destinationColor, arcColor,
      arcWidth, arcDashArray, curveHeight,
      originIconSize, destinationIconSize,
      travelModeIcon, travelIconColor, travelIconSize,
      originIcon, destinationIcon, travelIconRotation,
      labelSize, labelPosition, theme, cropAspectRatio,
      animations, colorPalette, mapStyle, labelFont
    };

    Object.entries(settings).forEach(([key, value]) => {
      try {
        localStorage.setItem(`flightPath_${key}`, JSON.stringify(value));
      } catch (e) {
        console.warn(`Error saving ${key} to localStorage:`, e);
      }
    });
  }, [
    originLat, originLng, destinationLat, destinationLng,
    originLabel, destinationLabel,
    originColor, destinationColor, arcColor,
    arcWidth, arcDashArray, curveHeight,
    originIconSize, destinationIconSize,
    travelModeIcon, travelIconColor, travelIconSize,
    originIcon, destinationIcon, travelIconRotation,
    labelSize, labelPosition, theme, cropAspectRatio,
    animations, colorPalette, mapStyle, labelFont
  ]);

  const extractGPSFromImage = (file, onSuccess) => {
    const reader = new FileReader();
    reader.onload = () => {
      EXIF.getData(file, function () {
        const lat = EXIF.getTag(this, 'GPSLatitude');
        const lng = EXIF.getTag(this, 'GPSLongitude');
        const latRef = EXIF.getTag(this, 'GPSLatitudeRef');
        const lngRef = EXIF.getTag(this, 'GPSLongitudeRef');

        if (lat && lng) {
          const decimalLat =
            (lat[0] + lat[1] / 60 + lat[2] / 3600) * (latRef === 'S' ? -1 : 1);
          const decimalLng =
            (lng[0] + lng[1] / 60 + lng[2] / 3600) * (lngRef === 'W' ? -1 : 1);
          onSuccess(decimalLat, decimalLng);
        } else {
          alert('No GPS data found in the image.');
        }
      });
    };
    reader.readAsArrayBuffer(file);
  };

  const handleOriginImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      extractGPSFromImage(file, (lat, lng) => {
        setOriginLat(lat);
        setOriginLng(lng);
      });
    }
  };

  const handleDestinationImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      extractGPSFromImage(file, (lat, lng) => {
        setDestinationLat(lat);
        setDestinationLng(lng);
      });
    }
  };

  const handleExport = () => {
    const svgElement = svgRef.current.querySelector('svg');
    if (!svgElement) {
      alert('SVG element not found.');
      return;
    }

    // Clone the SVG to avoid modifying the original
    const clonedSvg = svgElement.cloneNode(true);

    // If crop is enabled, transform screen coordinates to SVG coordinates
    if (cropEnabled) {
      // Get the SVG's current viewBox and dimensions
      const svgRect = svgElement.getBoundingClientRect();
      const viewBox = svgElement.viewBox.baseVal;

      // Calculate scale factors between screen pixels and SVG units
      const scaleX = viewBox.width / svgRect.width;
      const scaleY = viewBox.height / svgRect.height;

      // Transform crop bounds from screen coordinates to SVG coordinates
      const svgCropX = viewBox.x + (cropBounds.x * scaleX);
      const svgCropY = viewBox.y + (cropBounds.y * scaleY);
      const svgCropWidth = cropBounds.width * scaleX;
      const svgCropHeight = cropBounds.height * scaleY;

      clonedSvg.setAttribute('viewBox', `${svgCropX} ${svgCropY} ${svgCropWidth} ${svgCropHeight}`);
      clonedSvg.setAttribute('width', cropBounds.width);
      clonedSvg.setAttribute('height', cropBounds.height);
    }

    const serializer = new XMLSerializer();
    const svgString = serializer.serializeToString(clonedSvg);

    const blob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;

    // Generate file name
    let fileName = Array
      .from(originLabel)
      .filter((c) => c.match(/[a-zA-Z0-9]/))
      .join('');
    fileName += '-';

    fileName += Array
      .from(destinationLabel)
      .filter((c) => c.match(/[a-zA-Z0-9]/))
      .join('');

    fileName += '-by-';
    fileName += travelModeIcon.replace('Fa', '');

    link.download = `${fileName}.svg`;
    link.click();

    URL.revokeObjectURL(url);
  };

  const handleExportZip = async () => {
    const svgElement = svgRef.current.querySelector('svg');
    if (!svgElement) {
      alert('SVG element not found.');
      return;
    }

    // Generate base file name
    let baseName = Array.from(originLabel).filter((c) => c.match(/[a-zA-Z0-9]/)).join('');
    baseName += '-';
    baseName += Array.from(destinationLabel).filter((c) => c.match(/[a-zA-Z0-9]/)).join('');
    baseName += '-by-' + travelModeIcon.replace('Fa', '');

    // Clone and prepare SVG
    const clonedSvg = svgElement.cloneNode(true);

    // Handle crop if enabled
    if (cropEnabled) {
      const svgRect = svgElement.getBoundingClientRect();
      const viewBox = svgElement.viewBox.baseVal;
      const scaleX = viewBox.width / svgRect.width;
      const scaleY = viewBox.height / svgRect.height;
      const svgCropX = viewBox.x + (cropBounds.x * scaleX);
      const svgCropY = viewBox.y + (cropBounds.y * scaleY);
